package com.wjx871.population.security;import java.util.regex.*;import org.springframework.stereotype.Service;
@Service public class SensitiveDataMaskingService {private static final Pattern ID=Pattern.compile("(?<![0-9Xx])([0-9]{4})[0-9]{10}([0-9Xx]{4})(?![0-9Xx])"),PHONE=Pattern.compile("(?<!\\d)(1\\d{2})\\d{4}(\\d{4})(?!\\d)");public boolean canViewFull(){AuthenticatedUser u=CurrentUserContext.getUserOrNull();return u!=null&&u.permissions().contains("sensitive-data:view-full");}public String identity(String s){return canViewFull()?s:identityAlways(s);}public String phone(String s){return canViewFull()?s:phoneAlways(s);}public String permit(String s){return canViewFull()?s:permitAlways(s);}public String identityAlways(String s){return s==null?s:s.length()>=8?s.substring(0,4)+"**********"+s.substring(s.length()-4):"****";}public String phoneAlways(String s){return s==null?s:s.length()>=7?s.substring(0,3)+"****"+s.substring(s.length()-4):"****";}public String permitAlways(String s){return s==null?s:s.length()>=8?s.substring(0,4)+"****"+s.substring(s.length()-4):"****";}public String address(String s){if(s==null||canViewFull())return s;int i=Math.max(s.lastIndexOf('区'),Math.max(s.lastIndexOf('县'),s.lastIndexOf('市')));return i>=0?s.substring(0,i+1)+"（详细地址已隐藏）":"详细地址已隐藏";}public String filename(String s){return auditDetail(s);}public String auditDetail(String s){if(s==null)return null;String x=ID.matcher(s).replaceAll("$1**********$2");return PHONE.matcher(x).replaceAll("$1****$2").replaceAll("(?i)Bearer\\s+[A-Za-z0-9._-]+","Bearer ***").replaceAll("(?i)(password|密码)\\s*[:=]\s*[^,;\\s]+","$1=***");}}
